import{_ as t,C as a,o as r,c as o,H as i,Q as n}from"./chunks/framework.c4d6cd72.js";const b=JSON.parse('{"title":"Welcome","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),s={name:"index.md"},h=n('<h1 id="welcome" tabindex="-1">Welcome <a class="header-anchor" href="#welcome" aria-label="Permalink to &quot;Welcome&quot;">​</a></h1><p>Welcome to the <em>Fraud Intelligence Blockchain</em> (FIB) documentation.</p><p>FIB is a blockchain-based platform designed to combat fraud in various industries, including telecommunications, finance, and e-commerce.</p><p>This platform provides a secure and decentralized system for storing and sharing fraud-related information among participants to prevent potential fraudulent activities.</p><p>FIB operates on the <a href="/#what-is-iroha-2">Iroha 2 Hyperledger blockchain</a> and uses smart contracts to automate the exchange of fraud intelligence data. This platform enables organizations to securely share and access real-time information about known fraud events and other relevant data, allowing them to identify potential fraud attempts quicker and more accurately.</p><h2 id="where-to-start" tabindex="-1">Where to start? <a class="header-anchor" href="#where-to-start" aria-label="Permalink to &quot;Where to start?&quot;">​</a></h2><p>If you are new to FIB, start with the <a href="./overview.html">Overview</a> section, which provides a high-level introduction to the technology. This section explains what the FIB is, how it works, and other related concepts and terms.</p><p>For instructions on how to get started with the FIB, see the <a href="./getting-started.html">Getting Started</a> section. This section covers everything from setting up your FIB account to accessing the API, and integrating it into your existing workflows and systems.</p><p>For assistance with FIB Web UI, try the <a href="./tutorials-web.html">Tutorials: Web UI</a> section that walks you through basic operations that you can perform using the web interface.</p><p>If you&#39;re looking for step-by-step guidance on how to interact with the FIB API, check out the <a href="./tutorials-api.html">Tutorials: API</a> section where you can find a variety of scenarios to help you get started with the API.</p><p>Finally, the <a href="./api-specification.html">API Specification</a> section provides technical specification for the available endpoints explaining their internals exhaustively.</p><h2 id="what-is-iroha-2" tabindex="-1">What is Iroha 2? <a class="header-anchor" href="#what-is-iroha-2" aria-label="Permalink to &quot;What is Iroha 2? {#what-is-iroha-2}&quot;">​</a></h2><p><a href="https://github.com/hyperledger/iroha/tree/iroha2" target="_blank" rel="noreferrer">Iroha 2</a> is a blockchain hyperledger used to manage accounts, assets, and on-chain data storage with efficient smart contracts. The ledger is written in Rust and provides the following SDKs:</p><ul><li><a href="https://github.com/hyperledger/iroha-java/tree/iroha2-main" target="_blank" rel="noreferrer">Iroha Java/Kotlin</a></li><li><a href="https://github.com/hyperledger/iroha-python/tree/iroha2" target="_blank" rel="noreferrer">Iroha Python</a></li><li><a href="https://github.com/hyperledger/iroha-javascript/tree/iroha2" target="_blank" rel="noreferrer">Iroha Javascript</a></li><li><a href="https://github.com/hyperledger/iroha/tree/iroha2-lts/client" target="_blank" rel="noreferrer">Iroha Rust</a></li></ul><p>Check out the <a href="https://hyperledger.github.io/iroha-2-docs/" target="_blank" rel="noreferrer">Iroha 2 Documentation</a> as it provides an introduction to Iroha 2 as well as language-specific guides for Bash, Python, Rust, Kotlin/Java, and Javascript/TypeScript.</p><h2 id="getting-help" tabindex="-1">Getting help <a class="header-anchor" href="#getting-help" aria-label="Permalink to &quot;Getting help&quot;">​</a></h2><p>If, at any point, you’re experiencing any issues, please submit them at <a href="https://ragfraudblockchain.freshdesk.com/a/dashboard/default" target="_blank" rel="noreferrer">Fraud Intelligence Blockchain Freshdesk</a>. Upon review, someone will get back to you to resolve the issue.</p><p>Additionally, you may contact FIL via email at <strong><a href="mailto:support@fraudintelligencelimited.com" target="_blank" rel="noreferrer">support@fraudintelligencelimited.com</a></strong></p><hr>',19);function l(c,p,d,u,g,f){const e=a("CompaniesLogos");return r(),o("div",null,[h,i(e,{location:"docs"})])}const y=t(s,[["render",l]]);export{b as __pageData,y as default};
